def keep_features_dicts_synced(func):
    """
    Wrapper to keep the secondary dictionary, which tracks whether keys need to be decoded, in sync with the
    main dictionary of `Features`. It's used for the `Features` methods that modify the dictionary (e.g. `__setitem__`,
    `__delitem__`, `update`) so that `_column_requires_decoding` is always up to date, without having to
    subclass `UserDict` (which would introduce a big performance overhead and could break other things).
    """

    @wraps(func)
    def wrapper(*args, **kwargs):
        if args:
            self: "Features" = args[0]
            args = args[1:]
        else:
            self: "Features" = kwargs.pop("self")
        out = func(self, *args, **kwargs)
        assert hasattr(self, "_column_requires_decoding")
        self._column_requires_decoding = {col: require_decoding(feature) for col, feature in self.items()}
        return out

    wrapper.__doc__ = func.__doc__
    return wrapper


